import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2'
import { encodeBase64 } from "https://deno.land/std@0.203.0/encoding/base64.ts"

const SUPABASE_URL = Deno.env.get('SUPABASE_URL') ?? '';
const SUPABASE_SERVICE_KEY = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? '';

const PRIMARY_MODEL = "gemini-3-flash-preview";
const FALLBACK_MODEL = "gemini-2.5-flash";

const OCR_PROMPT = `BATCH OCR: Compare images, remove duplicates, and extract unique questions. Output JSON: { "questions": [ { "number": "string", "type": "string", "question_text": "string", "options": ["string"] } ] }`;

const SOLVER_PROMPT = (questions: string) => `SOLVE EXAM. Math to words only. No symbols. Short answers for mc/tf/fill. Provide steps for 'wo'. \n\nQUESTIONS: ${questions} \n\nOutput JSON: { "solutions": [ { "number": "string", "type": "string", "answer": "string", "steps": ["string"] } ] }`;

serve(async (req) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: { 'Access-Control-Allow-Origin': '*', 'Access-Control-Allow-Headers': '*' } });

  const requestId = Math.random().toString(36).substring(7).toUpperCase();
  const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_KEY);

  try {
    const payload = await req.json();
    if (payload.action !== 'process_staged_images') return new Response("Invalid Action", { status: 400 });

    // 1. Initialize DB Record
    const { data: record, error: insError } = await supabase
      .from('processed_images')
      .insert([{ status: 'processing' }])
      .select().single();
    if (insError) throw insError;

    console.log(`[${requestId}] Created Record: ${record.id}. Processing ${payload.paths.length} images.`);

    // 2. OCR STAGE (Must await here to prevent function suspension)
    const geminiParts = [{ text: OCR_PROMPT }];
    for (const path of payload.paths) {
      const { data: blob } = await supabase.storage.from('images').download(path);
      if (blob) {
        const buffer = await blob.arrayBuffer();
        geminiParts.push({ inline_data: { mime_type: "image/jpeg", data: encodeBase64(buffer) } } as any);
      }
    }

    const ocrRaw = await callGemini(supabase, PRIMARY_MODEL, geminiParts, requestId);
    const ocrJson = JSON.parse(extractJson(ocrRaw));

    // 3. SOLVER STAGE
    const qSummary = ocrJson.questions.map((q: any) => `${q.number}: ${q.question_text}`).join('\n');
    const solRaw = await callGemini(supabase, PRIMARY_MODEL, [{ text: SOLVER_PROMPT(qSummary) }], requestId);
    const solJson = JSON.parse(extractJson(solRaw));

    // 4. FINAL UPDATE
    const { error: updError } = await supabase.from('processed_images')
      .update({ 
        transcription: ocrJson, 
        solution_json: solJson, 
        status: 'completed' 
      })
      .eq('id', record.id);

    if (updError) throw updError;

    return new Response(JSON.stringify({ id: record.id }), { headers: { 'Content-Type': 'application/json' } });

  } catch (e) {
    console.error(`[${requestId}] Error:`, e.message);
    return new Response(JSON.stringify({ error: e.message }), { status: 500 });
  }
});

async function callGemini(supabase: any, model: string, parts: any[], requestId: string, retry = 0): Promise<string> {
  const { data: keyRow } = await supabase.from('api_keys')
    .select('api_key')
    .eq('service', 'gemini')
    .eq('is_active', true)
    .order('last_used_at', { ascending: true })
    .limit(1).single();

  if (!keyRow) throw new Error("No active Gemini API keys found.");

  const url = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${keyRow.api_key}`;
  const res = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ contents: [{ parts }], generationConfig: { response_mime_type: "application/json" } })
  });

  if (res.status === 429 && retry < 3) {
    return callGemini(supabase, FALLBACK_MODEL, parts, requestId, retry + 1);
  }

  const data = await res.json();
  if (!res.ok) throw new Error(data.error?.message || "AI Error");

  return data.candidates[0].content.parts[0].text;
}

function extractJson(raw: string) {
  const match = raw.match(/\{[\s\S]*\}/);
  return match ? match[0] : raw;
}

